namespace sv_298b58054b6a4b97ab17adf214f3a5a0.Services;

public class WarehouseInfo
{
    public required string Id { get; init; }
    public required string Name { get; init; }
}

/// <summary>
/// Scoped service that tracks the currently selected warehouse for one user circuit.
/// Components subscribe to <see cref="OnChange"/> to react when the selection changes.
/// </summary>
public class WarehouseState
{
    private static readonly List<WarehouseInfo> _warehouses =
    [
        new() { Id = "wh-1", Name = "Warehouse A – East" },
        new() { Id = "wh-2", Name = "Warehouse B – West" },
        new() { Id = "wh-3", Name = "Warehouse C – Central" },
    ];

    public IReadOnlyList<WarehouseInfo> AvailableWarehouses => _warehouses;

    public WarehouseInfo Current { get; private set; } = _warehouses[0];

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        var warehouse = _warehouses.FirstOrDefault(w => w.Id == warehouseId);
        if (warehouse is not null && warehouse.Id != Current.Id)
        {
            Current = warehouse;
            OnChange?.Invoke();
        }
    }
}

namespace sv_298b58054b6a4b97ab17adf214f3a5a0.Services;

/// <summary>
/// Scoped service that holds the latest low-stock alert count and notifies
/// all subscribed components when the count changes.
/// </summary>
public class InventoryAlertService
{
    private readonly Random _random = new();

    public int CurrentAlertCount { get; private set; }

    public event Action? OnChange;

    /// <summary>
    /// Simulates a database query that returns the number of items below minimum stock levels.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        var count = _random.Next(0, 16);
        return Task.FromResult(count);
    }

    /// <summary>
    /// Updates the cached alert count and notifies all subscribers.
    /// Called by the polling component after fetching fresh data.
    /// </summary>
    public void UpdateAlertCount(int newCount)
    {
        CurrentAlertCount = newCount;
        OnChange?.Invoke();
    }
}

