namespace sv_298b58054b6a4b97ab17adf214f3a5a0.Services;

/// <summary>
/// Scoped service that holds the latest low-stock alert count and notifies
/// all subscribed components when the count changes.
/// </summary>
public class InventoryAlertService
{
    private readonly Random _random = new();

    public int CurrentAlertCount { get; private set; }

    public event Action? OnChange;

    /// <summary>
    /// Simulates a database query that returns the number of items below minimum stock levels.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        var count = _random.Next(0, 16);
        return Task.FromResult(count);
    }

    /// <summary>
    /// Updates the cached alert count and notifies all subscribers.
    /// Called by the polling component after fetching fresh data.
    /// </summary>
    public void UpdateAlertCount(int newCount)
    {
        CurrentAlertCount = newCount;
        OnChange?.Invoke();
    }
}

