@* Interactive wrapper so this dropdown can handle change events inside the static layout. *@
@rendermode InteractiveServer
@inject WarehouseState WarehouseState
@implements IDisposable

<div class="warehouse-selector d-flex align-items-center gap-2">
    <label for="warehouse-select" class="text-nowrap fw-semibold">Warehouse:</label>
    <select id="warehouse-select"
            class="form-select form-select-sm"
            style="max-width: 220px;"
            value="@WarehouseState.Current.Id"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in WarehouseState.AvailableWarehouses)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var id = e.Value?.ToString();
        if (!string.IsNullOrEmpty(id))
        {
            WarehouseState.SetWarehouse(id);
        }
    }

    // Another component could also change the warehouse; stay in sync.
    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        WarehouseState.OnChange += _handler;
    }

    public void Dispose() => WarehouseState.OnChange -= _handler;
}

