@page "/dashboard"
@rendermode InteractiveServer
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Warehouse Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">Current Warehouse</h5>
        <p class="card-text fs-4">@WarehouseState.Current.Name</p>
    </div>
</div>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">
            Low-Stock Alerts
            @if (AlertService.CurrentAlertCount > 0)
            {
                <span class="badge bg-danger ms-2">@AlertService.CurrentAlertCount</span>
            }
            else
            {
                <span class="badge bg-success ms-2">All clear</span>
            }
        </h5>
        <p class="text-muted mb-0">
            Polling every 10 seconds for items below minimum levels.
            Last checked: @_lastChecked?.ToString("T")
        </p>
    </div>
</div>

@code {
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private DateTime? _lastChecked;
    private Action? _warehouseHandler;
    private Action? _alertHandler;

    protected override void OnInitialized()
    {
        // Re-render when the warehouse changes (selector is in MainLayout, not a parent).
        _warehouseHandler = () => InvokeAsync(OnWarehouseChangedAsync);
        WarehouseState.OnChange += _warehouseHandler;

        // Re-render when alert data arrives (the poll calls UpdateAlertCount,
